    """FIX 4 item 5: swap the Key-Findings HEADER label to the archetype's ``kf_title`` — CHROME
    ONLY. Rewrites at most the single leading ``## Key Findings`` header LINE to ``## {kf_title}``
    (e.g. a memo => ``## Bottom Line``); the one-sentence preamble and every finding BULLET are left
    byte-identical. A no-op (returns the input unchanged) when the block is empty, the archetype's
    kf_title is the canonical ``Key Findings``, or the canonical header is not the first line. PURE."""
    if not key_findings_md:
        return key_findings_md
    title = (getattr(archetype, "kf_title", "") or "").strip()
    if not title or title == "Key Findings":
        return key_findings_md
    _canonical = "## Key Findings\n"
    if key_findings_md.startswith(_canonical):
        return f"## {title}\n" + key_findings_md[len(_canonical):]
    return key_findings_md


