def _insert_banner_after_h1(report_md: str, banner: str) -> str:
    """FIX 4 (U6): insert the D8-unadjudicated ``banner`` AFTER the report's H1 title block so the
    report opens on the ``# `` title, not on a disclosure blockquote. The banner STRING is placed
    VERBATIM (byte-identical — no builder edit). "After the H1 title block" = immediately after the
    first line that starts with ``# `` and its trailing blank line(s). Falls back to a PREPEND when
    no H1 is present (the banner must still ship — a disclosure is never silently dropped). PURE."""
    if not report_md:
        return banner + report_md
    lines = report_md.split("\n")
    h1_idx = None
    for i, ln in enumerate(lines):
        if ln.startswith("# ") and not ln.startswith("## "):
            h1_idx = i
            break
    if h1_idx is None:
        return banner + report_md  # no H1 => fail-safe prepend (banner still ships)
    # Advance past the H1 line and any immediately-following blank lines so the banner sits in the
    # gap between the title and the first body block.
    insert_at = h1_idx + 1
    while insert_at < len(lines) and lines[insert_at].strip() == "":
        insert_at += 1
    head = "\n".join(lines[:insert_at])
    tail = "\n".join(lines[insert_at:])
    # Keep a blank line between the title block and the banner, and preserve the banner's own bytes.
    return head + "\n\n" + banner + tail


